function ACCEPT()
{


	if(Ctrl('main').GetMode() == "NEW-PASO5" || Ctrl('main').GetMode() == "NEW-PASO5-NEW" || Ctrl('main').GetMode() == "EDIT-PASO5" || Ctrl('main').GetMode() == "EDIT-PASO5-NEW" ||Ctrl('main').GetMode() == "EDIT-EDIT-MONTOS" )
	{                           
		if(Ctrl('oi_tipo_monto').GetXValue() == "")
		{	
			alert("Debe completar el tipo de monto");
			return false;
		}            
		else
			Ctrl('main').DoEvent("ACCEPT");	
	}
	else
			{	//Si es ACCEPT en modo NEW-PASO5-f o EDIT-PASO5-DEL pregunta si realmente quiere salir ya que no se modifico
				if((Ctrl('main').GetMode() == "NEW-PASO5-DEL") || ((Ctrl('main').GetMode() == "EDIT-PASO5-DEL")) )
						{
							var cantidadActual = Ctrl('MAIN_GRID').TotalRowsCount();						
							if(Ctrl('hid_cant_rows_del').GetCValue()==cantidadActual)
								{
								alert('Esta saliendo sin eliminar montos, elimine algún monto o presione Cancelar para salir');
								return false;
								}
									else
									{						
									Ctrl('main').DoEvent("ACCEPT");
									}							
						}
						else
							{							
							Ctrl('main').DoEvent("ACCEPT");
							}		 

			}
}


function SetValorMonto()
{ 
	var MyControlMontoPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_prev');
	var MyControlPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_prevision');

	var MyControlMontoPrevCosto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_prev_c');
	var MyControlPrevCosto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_prevision_c');

	var MyControlMonto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto');

	if(MyControlPrev.GetXValue() != "")
	{   
		var calculo;              
		var prevision = MyControlPrev.TypedValue() / 100.00;
		calculo = MyControlMonto.TypedValue() * prevision;

		MyControlMontoPrev.SetTypedValue(calculo);
		MyControlMontoPrev.SetEnabled(false); 

		var MontoPrevCosto = calculo * MyControlPrevCosto.TypedValue() / 100.00;
		MyControlMontoPrevCosto.SetTypedValue(MontoPrevCosto);
		MyControlMontoPrevCosto.SetEnabled(false); 
	}
	else
	{                                   
		MyControlMontoPrev.SetXValue("");
		MyControlMontoPrev.SetEnabled(true);             

		MyControlMontoPrevCosto.SetTypedValue("");
		MyControlMontoPrevCosto.SetEnabled(false); 
	}	
}


function SetValorPrev()
{ 
	var MyControlMontoPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_prev');
	var MyControlPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_prevision');

	var MyControlMontoPrevCosto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_prev_c');
	var MyControlPrevCosto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_prevision_c');

	var MyControlMonto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto');

	if(MyControlMontoPrev.GetXValue() != "")
	{   
		var calculo;              

		calculo = MyControlMontoPrev.TypedValue() * 100.00 / MyControlMonto.TypedValue();

		MyControlPrev.SetTypedValue(calculo);
		MyControlPrev.SetEnabled(false);

		var MontoPrevCosto = calculo * MyControlPrevCosto.TypedValue() / 100.00;
		MyControlMontoPrevCosto.SetTypedValue(MontoPrevCosto);
		MyControlMontoPrevCosto.SetEnabled(false); 
	}
	else
	{                                   
		MyControlPrev.SetXValue("");
		MyControlPrev.SetEnabled(true);

		MyControlMontoPrevCosto.SetTypedValue("");
		MyControlMontoPrevCosto.SetEnabled(false); 
	}
}                         

function SetValores()
{              

	var MyControlMontoPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_prev');
	var MyControlPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_prevision');


	if(MyControlPrev.GetXValue() != "")
		SetValorMonto();
	else
		if(MyControlMontoPrev.GetXValue() != "")
			SetValorPrev();
}

function NEXT()
{
	if(Ctrl('main').GetMode() == "NEW-PASO1-ADMIN" || Ctrl('main').GetMode() ==="NEW-PASO1-USER" || Ctrl('main').GetMode() == "EDIT-PASO1")
		Ctrl('id_tipo_carpeta').SetXValue(Ctrl('oi_tipo_carpeta').GetXValue());

	if(Ctrl('main').GetMode() == "NEW-PASO2" || Ctrl('main').GetMode() == "EDIT-PASO2" )
	{
		if(Ctrl("LIST").RowsCount() < 1)
		{
			alert("Debe agregar al menos una Parte Interviniente.");
			return false;                           
		}             
		else
		{
			np = new NomadProxy("", ut);
			nSQL = np.SQLService();
			var validacion = nSQL.GetOBJ(Ctrl("main").getResource("getRolesObligatorios"), ""); 
		 	var existe_parte;
		 	var mensaje = "";                      

		 	//RECORRO LAS ROLES CREADOS.
		 	for (var i = 0; i<validacion.Child.length; i++) {
		 		//BUSCO LOS ROLES QUE SON OBLIGATORIOS COMO PARTES.
				if(validacion.Child[i].c_partes == "1")
				{

					existe_parte = 0;                                  
					//RECORRO LAS PARTES CARGADAS EN EL CONFLICTO.                   
					for (var j=0; j<Ctrl('resultado').CountRow(); j++)
					{
						if(Ctrl("resultado").GetRow(j).GetAttr("rol") == validacion.Child[i].oi_rol)
							existe_parte = 1;
					}                                                                    

					if(existe_parte == 0)
						mensaje += "El rol " + validacion.Child[i].d_rol + " es obligatorio como parte interviniente. \r\n"
				}				
			}
			 if(mensaje == "")
		  	Ctrl('main').DoEvent("NEXT");
		  else
		  {   
		  	alert(mensaje);
		  	return false;
		  } 

		}

	}
	if(Ctrl('main').GetMode() == "NEW-PASO3" || Ctrl('main').GetMode() == "EDIT-PASO3")
	{                                                              

		var msj="";
		var existe;

		if(Ctrl("LIST2").TotalRowsCount() > 0)
			Ctrl('objeto_creado').SetXValue("1");
		else
			Ctrl('objeto_creado').SetXValue("0");			

		if(Ctrl("resultado").CountRow() == 0 && Ctrl('c_req_obj_carpeta').GetXValue() == "1")
		{
			alert("Debe agregar al menos un objeto de reclamo por Parte Interviniente.");
			return false;
		}                                                                                    
		if(Ctrl('c_req_obj_carpeta').GetXValue() == "1")
		{
			for (var i=0; i<Ctrl("LIST").TotalRowsCount(); i++)
			{
				existe = 0;
				for (var j=0; j<Ctrl("LIST2").TotalRowsCount(); j++)
				{	
					if((Ctrl("LIST").GetAttrValue(i, 'sujeto') == Ctrl("LIST2").GetAttrValue(j, 'sujeto')) && Ctrl("LIST2").GetAttrValue(j, 'l_inactivo') == 0)
					{
						existe = 1;
					}
				}
				if(existe == 0)
				{	
					var nSQL = GetProxy().SQLService();
					var DescSujeto = nSQL.GetOBJ(Ctrl("main").getResource("GetDescSujeto"), "<PARAM oi_sujeto=\""+Ctrl("LIST").GetAttrValue(i, 'sujeto')+"\" />"); 
					msj += "El Sujeto " + DescSujeto.d_sujeto + " no tiene cargado ningún objeto de reclamo activo. Debe cargarle uno. \r\n";
				}
			}
			if(msj != "")
			{
				alert(msj);
				return false;
			}             
			else
				Ctrl('main').DoEvent("NEXT");
		}
		else
				Ctrl('main').DoEvent("NEXT");
	}
	if(Ctrl('main').GetMode() == "NEW-PASO6")
	{                                                
		if(Ctrl("LIST").RowsCount() < 1)
			Ctrl('hid_cant_tareas').SetXValue("0");
		else
			Ctrl('hid_cant_tareas').SetXValue(Ctrl("LIST").RowsCount());		
		Ctrl('main').DoEvent("NEXT");	
	}
	if(Ctrl('main').GetMode() == "NEW-PASO7")
	{                                                
		if(Ctrl("LIST").RowsCount() < 1)
			Ctrl('hid_cant_documentos').SetXValue("0");
		else
			Ctrl('hid_cant_documentos').SetXValue(Ctrl("LIST").RowsCount());		
		Ctrl('main').DoEvent("NEXT");	
	}

} 



