function refreshList(strList, arr)
{                    
	Ctrl(strList).processResult(array2string(arr));
}

function string2array(str)
{
	var arr = new Array();
	var auxXml = new nomadDOM(str);

	for (i=0; i<auxXml.Child.length; i++)
	{
		arr["k" + auxXml.Child[i].id]=auxXml.Child[i];
	}
	return arr;
}

function array2string(arr)
{
	var retval = "";
	var key;
	for (key in arr)
	{
		retval+=ELE2String(arr[key].associatedELE);
	}

	return "<ROWS>"+retval+"</ROWS>";
}

function refrescarLista()
{
	Ctrl('resultado').DelAllRow();
 	for (key in arrA)
 	{          
 		var rowDestinatarios = Ctrl('resultado').AddRow();
 		rowDestinatarios.SetAttr('id', key.substr(1));
 	}                           
}

function ADD()
{                                                                  
	if((Ctrl('main').GetMode() != "NEW-PASO3") && (Ctrl('main').GetMode() != "EDIT-PASO3")&& (Ctrl('main').GetMode() != "EDIT-OBJETO"))
	{
		var validacion = "";
		if((Ctrl('main').GetMode() == "NEW-PASO7") || (Ctrl('main').GetMode() == "EDIT-PASO7") || (Ctrl('main').GetMode() == "EDIT-DOCUMENTOS") || (Ctrl('main').GetMode() == "EDIT-DOCS"))
			if(Ctrl('oi_tarea').GetXValue() != "")
				Ctrl('d_tarea').SetXValue(Ctrl('oi_tarea').GetCValue());			
		  else
				Ctrl('d_tarea').SetXValue('');					  	
		if((Ctrl('main').GetMode() == "NEW-PASO2") || (Ctrl('main').GetMode() == "EDIT-PASO2") || (Ctrl('main').GetMode() == "EDIT-PARTES"))
		{
			for (var l=0; l<Ctrl("LIST").TotalRowsCount(); l++)
			{
				if(Ctrl("LIST").GetAttrValue(l, 'sujeto') == Ctrl('oi_sujeto').GetXValue())
					validacion = "No se puede agregar el sujeto porque ya existe como parte.";
			}
		}
		if((Ctrl('main').GetMode() == "NEW-PASO6") || (Ctrl('main').GetMode() == "EDIT-PASO6"))
		{
			var desc = Ctrl('oi_clasif_sujeto').GetCValue().split(' - ');
			Ctrl('hid_d_clasif_sujeto').SetXValue(desc[1]);
			for (var l=0; l<Ctrl("LIST").TotalRowsCount(); l++)
			{
				if(Ctrl("LIST").GetAttrValue(l, 'desc_tarea') == Ctrl('d_tarea').GetXValue())
					validacion = "No se puede agregar la tarea porque ya existe.";
			}
		}	


		if(Ctrl("main").GetMode() == "NEW-PASO9" || Ctrl("main").GetMode() == "EDIT-RADICACION"|| Ctrl("main").GetMode() == "EDIT-RADICACION-SHOW") 
			{
	      for (var j=0; j<Ctrl('resultado').CountRow(); j++)
					{     			        
			       Ctrl("resultado").GetRow(j).SetAttr('l_vigente','0');
					}		  
			}		 			
		if(validacion!="")
		{
			alert(validacion);
			return false;
		}
		else
		{ 
		  var MyControl = Ctrl("LIST");
			refreshList("LIST", arrA);

			Ctrl('main').DoEvent("REFRESCAR");

		}
	}
	else
	{                                 
		np = new NomadProxy("", ut);
		nSQL = np.SQLService();
		var msj="";
		if (Ctrl("list1arr") && Ctrl("list1arr").CountRow()>0)
		{ //Caso que hay esta checkeado elementos en la lista
			var List2Id=0;
			var List2IdNew;
			var retval_final = "";
			for (var j=0; j<Ctrl('resultado').CountRow(); j++)
			{
				//retval+="<ROW id=\""+ Ctrl("resultado").GetRow(j).GetAttr("id") +"\" rol=\"" + Ctrl("resultado").GetRow(j).GetAttr("rol") +"\" sujeto=\"" + Ctrl("resultado").GetRow(j).GetAttr("sujeto") +"\" objeto_reclamo=\"" + Ctrl("resultado").GetRow(j).GetAttr("objeto_reclamo")+"\" causa=\"" + "" +"\" />";

				var retval = new NomadXML("ROW");
				retval.SetAttr("id", Ctrl("resultado").GetRow(j).GetAttr("id"));
				retval.SetAttr("rol", Ctrl("resultado").GetRow(j).GetAttr("rol"));
				retval.SetAttr("sujeto", Ctrl("resultado").GetRow(j).GetAttr("sujeto"));
				retval.SetAttr("objeto_reclamo", Ctrl("resultado").GetRow(j).GetAttr("objeto_reclamo"));
				retval.SetAttr("l_inactivo", Ctrl("resultado").GetRow(j).GetAttr("l_inactivo"));

				retval_final+=retval.ToString();

				if(List2Id < Ctrl("resultado").GetRow(j).GetAttr("id"))
					List2Id = Ctrl("resultado").GetRow(j).GetAttr("id");      
			}             
			List2IdNew = List2Id;
			while(Ctrl("list1arr").CountRow()>0)
			{                                
				//Obtengo el ID del Elemento		
				MyID=Ctrl("list1arr").GetRow(0).GetAttr("id"); 
				for (var j=0; j<Ctrl("LIST").TotalRowsCount(); j++)
				{                      
					if (MyID == Ctrl("LIST").GetAttrValue(j, 'id'))
					{
						List2IdNew++;                                
						//PARAM = "<PARAM rol=\""+Ctrl("LIST").GetAttrValue(j, 'rol')+"\" sujeto=\""+Ctrl("LIST").GetAttrValue(j, 'sujeto')+"\" />";
						//var GetOI = nSQL.GetOBJ(Ctrl("main").getResource("GetOIParte"), PARAM); 
						var existe = 0;
						for (var k=0; k<Ctrl("LIST2").TotalRowsCount(); k++)
						{
							if((Ctrl("LIST").GetAttrValue(j, 'sujeto') == Ctrl("LIST2").GetAttrValue(k, 'sujeto')) && (Ctrl('oi_objeto_reclamo').GetXValue() == Ctrl("LIST2").GetAttrValue(k, 'objeto_reclamo')))
								existe = 1;
						}
						if(existe == 0)
						{
							var rowList2arr = Ctrl('resultado').AddRow();
	 						rowList2arr.SetAttr("id"						, List2IdNew);
							rowList2arr.SetAttr("rol"						, Ctrl("LIST").GetAttrValue(j, 'rol'));
							rowList2arr.SetAttr("sujeto"				, Ctrl("LIST").GetAttrValue(j, 'sujeto'));
							rowList2arr.SetAttr("desc_rol"			, Ctrl("LIST").GetAttrValue(j, 'desc_rol'));
							rowList2arr.SetAttr("desc_sujeto"		, Ctrl("LIST").GetAttrValue(j, 'desc_sujeto'));
							rowList2arr.SetAttr("objeto_reclamo", Ctrl('oi_objeto_reclamo').GetXValue());
							rowList2arr.SetAttr("d_objeto_reclamo", Ctrl('oi_objeto_reclamo').GetCValue());
							rowList2arr.SetAttr("l_inactivo"    , "0"); 
							rowList2arr.SetAttr("causa"					, "");
							rowList2arr.SetAttr("delete"				, "1");
						}
						else
						{
							msj+= "No se puede agregar el objeto de reclamo sujeto: " + Ctrl("LIST").GetAttrValue(j, 'desc_sujeto') +" Objeto de Reclamo: " + Ctrl('oi_objeto_reclamo').GetCValue() + " porque ya existe. \r\n";
						}
						Ctrl('list1arr').DelRow(0);
					}
				}				
			}
			for (var j=0; j<Ctrl('resultado').CountRow(); j++)
				//retval+="<ROW id=\""+ Ctrl("resultado").GetRow(j).GetAttr("id") +"\" rol=\"" +Ctrl("resultado").GetRow(j).GetAttr("rol")+"\" sujeto=\"" +Ctrl("resultado").GetRow(j).GetAttr("sujeto")+"\" desc_rol=\"" + Ctrl("resultado").GetRow(j).GetAttr("desc_rol") +"\" desc_sujeto=\"" + Ctrl("resultado").GetRow(j).GetAttr("desc_sujeto") +"\" objeto_reclamo=\"" + Ctrl("resultado").GetRow(j).GetAttr("objeto_reclamo")+"\" causa=\"" + "" +"\" delete=\""+Ctrl("resultado").GetRow(j).GetAttr("delete")+"\" />";
			{	
			  var retval = new NomadXML("ROW");
				retval.SetAttr("id", Ctrl("resultado").GetRow(j).GetAttr("id"));
				retval.SetAttr("rol", Ctrl("resultado").GetRow(j).GetAttr("rol"));
				retval.SetAttr("sujeto", Ctrl("resultado").GetRow(j).GetAttr("sujeto")); 
				retval.SetAttr("desc_rol", Ctrl("resultado").GetRow(j).GetAttr("desc_rol")); 
				retval.SetAttr("desc_sujeto", Ctrl("resultado").GetRow(j).GetAttr("desc_sujeto"));
				retval.SetAttr("objeto_reclamo", Ctrl("resultado").GetRow(j).GetAttr("objeto_reclamo"));  //***3 recarga la lista
				retval.SetAttr("l_inactivo", Ctrl("resultado").GetRow(j).GetAttr("l_inactivo"));
				retval.SetAttr("delete", Ctrl("resultado").GetRow(j).GetAttr("delete")); 

				retval_final+=retval.ToString();
      }
			var result = "<ROWS>"+retval_final+"</ROWS>";			
			arrB = new Array(); 
			arrB = string2array(result);
			refreshList("LIST2", arrB);
		}		
		unmark_list();
		if(msj!="")
			alert(msj);
	}	



}

function DEL()  
{
	var MyID;
	var del;
	var msj="";
	var registro;
	var itemsToDel = new Array();
	var item = 0;
	if (Ctrl("list1arr") && Ctrl("list1arr").CountRow()>0)   //si hay elementos checkeados
	{ 

	//Si es documentos confirmo
	if(Ctrl('main').GetMode() == "EDIT-DOCUMENTOS" || Ctrl('main').GetMode() == "EDIT-DOCS")
		{
		  	var msjDoc ='¿Confirma eliminar permanentemente el Documento de la Carpeta?';
		  	if(!(confirm(msjDoc)))
		  		{
		  		  return false;                	
		  		}
		}

		while(Ctrl("list1arr").CountRow()>0)
		{                                

			//Obtengo el id del elemento seleccionado		
			MyID=Ctrl("list1arr").GetRow(0).GetAttr("id");

			for (var j=0; j<Ctrl("LIST").TotalRowsCount(); j++)  //para cada elemento de la lista
			{
				if (MyID == Ctrl("LIST").GetAttrValue(j, 'id'))  //si el elemento está seleccionado
				{
					del = Ctrl("LIST").GetAttrValue(j, 'delete');  
					registro = j;  
				}
			}
			//Elimino el Elemento
			if (Ctrl("list1arr")) 
			{
				itemsToDel[item] = MyID;
				Ctrl("list1arr").DelRow(0);
			}
			if((Ctrl('main').GetMode() == "NEW-PASO2") || (Ctrl('main').GetMode() == "EDIT-PASO2")|| (Ctrl('main').GetMode() == "EDIT-PARTES"))
			{
				if(del == "1")
				{
					delete arrA["k"+MyID];    
					Ctrl('resultado').DelRowByAttr('id', MyID);
				}
				else
				{
					msj+= "La parte interviniente: " + Ctrl("LIST").GetAttrValue(registro, 'desc_rol')+'-'+Ctrl("LIST").GetAttrValue(registro, 'desc_sujeto')+" tiene un monto creado. \r\n"
				}
			}
			else
			{
				delete arrA["k"+MyID];    
				Ctrl('resultado').DelRowByAttr('id', MyID);
			}
			item++; 			
		}
		if(msj!="")
		{
			msj+= "¿Desea eliminarla(s)?";
			if(confirm(msj))         
			{  
				for(var k=0;k<itemsToDel.length;k++)
				{                                
				  //Obtengo el ID del Elemento		
					MyID=itemsToDel[k];
					delete arrA["k"+MyID];    
					Ctrl('resultado').DelRowByAttr('id', MyID);
				}

					Ctrl('main').DoEvent("DELETE");

			}
		}
	} 
	refreshList("LIST", arrA);	
}

function DEL2()
{

	var MyID;
	var del;
	var msj="";
	var registro;
	var itemsToDel = new Array();
	var item = 0;

	if (Ctrl("list2arr") && Ctrl("list2arr").CountRow()>0)
	{ //Caso que hay esta checkeado elementos en la lista
		while(Ctrl("list2arr").CountRow()>0)
		{                                
			//Obtengo el ID del Elemento		
			MyID=Ctrl("list2arr").GetRow(0).GetAttr("id");

			for (var j=0; j<Ctrl("LIST2").TotalRowsCount(); j++)
			{
				if (MyID == Ctrl("LIST2").GetAttrValue(j, 'id')) 
				{
					del = Ctrl("LIST2").GetAttrValue(j, 'delete');  
					registro = j;  
				}
			}

			//Elimino el Elemento
			if (Ctrl("list2arr")) 
			{
				itemsToDel[item] = MyID;
				Ctrl("list2arr").DelRow(0);           
			}
			if(del == "1")
			{
				delete arrB["k"+MyID];    
				Ctrl('resultado').DelRowByAttr('id', MyID);
			}
			else
			{								

			  var oi_objeto_reclamo = Ctrl("LIST2").GetAttrValue(registro, 'objeto_reclamo');
			  var nSQL = GetProxy().SQLService();	 
				var param = "<DATA oi_objeto_reclamo=\""+oi_objeto_reclamo+"\" />"; 
		 		var objObjRec = nSQL.GetOBJ(Ctrl("main").getResource("GetDescObj"),param);	
				var d_objeto_reclamo =  objObjRec.d_objeto_reclamo;

				msj+= "El objeto de reclamo: " + Ctrl("LIST2").GetAttrValue(registro, 'desc_rol')+'-'+Ctrl("LIST2").GetAttrValue(registro, 'desc_sujeto')+"-"+d_objeto_reclamo+'-'+" no se puede eliminar ya que tiene un monto creado. \r\n"
			}
			item++;
		}
		//if(msj!="")
			//alert(msj);
		if(msj!="")
		{
			msj+= "¿Desea eliminarlo(s)?";
			if(confirm(msj))         
			{  
				for(var k=0;k<itemsToDel.length;k++)
				{                                
				  //Obtengo el ID del Elemento		
					MyID=itemsToDel[k];
					delete arrB["k"+MyID];    
					Ctrl('resultado').DelRowByAttr('id', MyID);
				}
				if(Ctrl('main').GetMode()=="EDIT-OBJETO")			
					Ctrl('main').DoEvent("DELETE");
			}
		}
	} 
	refreshList("LIST2", arrB);	
}

function DEL_ALL()
{

	var key;
	var newArrA=new Array();
	var del;
	var msj="";
	var registro;

	for (key in arrA)
	{

		//Son los registros chequeados
		if (Ctrl("list1arr").GetRowByAttr("id",key.substr(1))!=null)
		{
			newArrA[key]=arrA[key];		

		}
		else
		{ 
			for (var j=0; j<Ctrl("LIST").TotalRowsCount(); j++)
			{	         

				if (key.substr(1) == Ctrl("LIST").GetAttrValue(j, 'id')) 
				{

					del = Ctrl("LIST").GetAttrValue(j, 'delete');
					registro = j;    
				}
			}   			


				if((Ctrl('main').GetMode() == "NEW-PASO2") || (Ctrl('main').GetMode() == "EDIT-PASO2")|| (Ctrl('main').GetMode() == "EDIT-PARTES"))
				{

