function EDIT_TAREA()
{
	var row;    
	if(IdTareaSel!="")
	{
		for (var j=0; j<Ctrl("LIST").TotalRowsCount(); j++)
			if (IdTareaSel == Ctrl("LIST").GetAttrValue(j, 'id')) 
				row=j;
		Ctrl("LIST").SetAttrValue(row, "desc_tarea"		, Ctrl("d_tarea").GetXValue());
		Ctrl("LIST").SetAttrValue(row, "f_alta"				, Ctrl("f_tarea").GetXValue());
		Ctrl("LIST").SetAttrValue(row, "estado"				, Ctrl("oi_estado_tarea").GetXValue());
		Ctrl("LIST").SetAttrValue(row, "tipo_tarea"		, Ctrl("oi_tipo_tarea").GetXValue());
		var desc = Ctrl('oi_clasif_sujeto').GetCValue().split(' - ');
		Ctrl("LIST").SetAttrValue(row, "desc_responsable"	, desc[1]);
		Ctrl("LIST").SetAttrValue(row, "lugar"				, Ctrl("d_lugar_tarea").GetXValue());
		Ctrl("LIST").SetAttrValue(row, "f_vencimiento", Ctrl("f_vto_tarea").GetXValue());
		Ctrl("LIST").SetAttrValue(row, "observacion"	, Ctrl("o_tarea").GetXValue());

		//RECORRO LAS TAREAS. 
		for (var i=0; i<Ctrl('resultado').CountRow(); i++)
			if(Ctrl("resultado").GetRow(i).GetAttr("id") == IdTareaSel)
			{                                           
				Ctrl("resultado").GetRow(i).SetAttr("desc_tarea"	 , Ctrl("d_tarea").GetXValue());
				Ctrl("resultado").GetRow(i).SetAttr("f_alta"			 , Ctrl("f_tarea").GetXValue());
				Ctrl("resultado").GetRow(i).SetAttr("estado"	 		 , Ctrl("oi_estado_tarea").GetXValue());
				Ctrl("resultado").GetRow(i).SetAttr("tipo_tarea"	 , Ctrl("oi_tipo_tarea").GetXValue());
				var desc = Ctrl('oi_clasif_sujeto').GetCValue().split(' - ');
				Ctrl("resultado").GetRow(i).SetAttr("desc_responsable"	 , desc[1]);                    
				Ctrl("resultado").GetRow(i).SetAttr("responsable"	 , Ctrl("oi_clasif_sujeto").GetXValue());
				Ctrl("resultado").GetRow(i).SetAttr("lugar"				 , Ctrl("d_lugar_tarea").GetXValue());
				Ctrl("resultado").GetRow(i).SetAttr("f_vencimiento", Ctrl("f_vto_tarea").GetXValue());
				Ctrl("resultado").GetRow(i).SetAttr("observacion"	 , Ctrl("o_tarea").GetXValue());
			}
	}
	else
	{
		alert("No hay tarea seleccionada para ser modificada.");
		return false;
	}
}    
