function ACCEPT_PARTES_onClick()
{
   if(Ctrl("LIST").RowsCount() < 1)
		{
			alert("Debe agregar al menos una Parte Interviniente.");
			return false;                           
		}             
		else
		{
			np = new NomadProxy("", ut);
			nSQL = np.SQLService();
			var validacion = nSQL.GetOBJ(Ctrl("main").getResource("getRolesObligatorios"), ""); 
		 	var existe_parte;
		 	var mensaje = "";                      

		 	//RECORRO LAS ROLES CREADOS.
		 	for (var i = 0; i<validacion.Child.length; i++) {
		 		//BUSCO LOS ROLES QUE SON OBLIGATORIOS COMO PARTES.
				if(validacion.Child[i].c_partes == "1")
				{

					existe_parte = 0;                                  
					//RECORRO LAS PARTES CARGADAS EN EL CONFLICTO.

					for (var j=0; j<Ctrl('resultado').CountRow(); j++)
					{

						if(Ctrl("resultado").GetRow(j).GetAttr("rol") == validacion.Child[i].oi_rol)
							existe_parte = 1;
					}                                                                    

					if(existe_parte == 0)
						mensaje += "El rol " + validacion.Child[i].d_rol + " es obligatorio como parte interviniente. \r\n"
				}				
			}
			 if(mensaje == "")
			 	{		 	  
		 		return true;		  
		 		}	

		  else
		  {   
		  	alert(mensaje);
		  	return false;
		  } 

		}	
}

function ACCEPT_OBJETOS_onClick()
{
  var msj="";
	var existe;


		if(Ctrl("LIST2").TotalRowsCount() > 0)
			Ctrl('objeto_creado').SetXValue("1");
		else
			Ctrl('objeto_creado').SetXValue("0");			

		if(Ctrl("resultado").CountRow() == 0 && Ctrl('c_req_obj_carpeta').GetXValue() == "1")
		{
			alert("Debe agregar al menos un objeto de reclamo por Parte Interviniente.");
			return false;
		}                                                                                    
		if(Ctrl('c_req_obj_carpeta').GetXValue() == "1")
		{
			for (var i=0; i<Ctrl("LIST").TotalRowsCount(); i++)
			{
				existe = 0;
				for (var j=0; j<Ctrl("LIST2").TotalRowsCount(); j++)
				{	
					if((Ctrl("LIST").GetAttrValue(i, 'sujeto') == Ctrl("LIST2").GetAttrValue(j, 'sujeto')) && Ctrl("LIST2").GetAttrValue(j, 'l_inactivo') == 0 )
					{
						existe = 1;
					}
				}
				if(existe == 0)
				{	
					var nSQL = GetProxy().SQLService();
					var DescSujeto = nSQL.GetOBJ(Ctrl("main").getResource("GetDescSujeto"), "<PARAM oi_sujeto=\""+Ctrl("LIST").GetAttrValue(i, 'sujeto')+"\" />"); 
					msj += "El Sujeto " + DescSujeto.d_sujeto + " no tiene cargado ningún objeto de reclamo activo. Debe cargarle uno o activar uno existente. \r\n";
				}
			}
			if(msj != "")
			{
				alert(msj);
				return false;
			}             
			else
			return true;
		}
		else
			return true;
} 

