function SAVE_EDIT_onClick()
{ 

	if((Ctrl('objeto_creado').GetXValue() == "0") && (Ctrl('c_req_obj_carpeta').GetXValue() == "1"))
	{
		alert("Debe cargar los Objetos Reclamo");
		return false;
	}

	if((Ctrl('monto_creado').GetXValue() == "0") && (Ctrl('c_req_carga_monto').GetXValue() == "1"))
	{
		alert("Debe cargar los montos antes de guardar el conflicto");
		return false;
	}
	if((Ctrl('atributo_creado').GetXValue() == "0") && (Ctrl('c_req_atr_proc').GetXValue() == "1"))
	{
		alert("Debe cargar los atributos procesales antes de guardar el conflicto");
		return false;
	}
	if((Ctrl('radicacion_creado').GetXValue() == "0") && (Ctrl('c_req_rad_tram').GetXValue() == "1"))
	{
		alert("Debe cargar la radicación del trámite antes de guardar el conflicto");
		return false;
	}

	return true;

}

