function BAJA_onClick()
{
  var id;

	if(Ctrl('main').GetMode() == "LIST")
	{
		   id=Ctrl("LIST").GetXValue();
	}
	if(Ctrl('main').GetMode() == "SHOW") 
	{
	  var id = Ctrl('oi_carpeta').GetXValue();

	}	

	var param = "<DATA oi_carpeta=\""+id+"\" />";	 


		//valido que no este de baja	  	 
	  var nSQL2 = GetProxy().SQLService();
	  var nSQL3 = GetProxy().SQLService();	 	 
		var param2 = "";                       		 

		var objOiBaja = nSQL2.GetOBJ(Ctrl("main").getResource("Get_oi_Baja"),param2);			
		var oiEstado = nSQL3.GetOBJ(Ctrl("main").getResource("getEstadoCarpeta"),param);			 
		if(oiEstado.oi_estado_carpeta==objOiBaja.oi)
			{
				alert("La Carpeta ya esta dada de Baja");
				 return false
			} 

	 //valida que la carpeta no tenga adelantos
	 	var nSQL4 = GetProxy().SQLService();
		var tieneAdelantos = nSQL4.GetOBJ(Ctrl("main").getResource("tieneAdelantos"),param);
			if(tieneAdelantos.a==1)
			{
				alert("No puede darse de baja porque la carpeta posee adelantos cargados.");
				return false
			}   

		//valida que la carpeta no tenga tareas a completar o asignadas
	 	var nSQL5 = GetProxy().SQLService();
		var tieneTareas = nSQL5.GetOBJ(Ctrl("main").getResource("tieneTareas"),param);
			if(tieneTareas.a==1)
			{
				alert("No puede darse de baja porque la carpeta posee tareas a completar o asignadas.");
				return false
			}

   openNewFlowWait("NucleusRH.Base.Legales.Carpetas.CAMBIOS.flow", "open_externo_baja", '<PARAMS oi_carpeta="'+id+'" />', objTemp);
} 

