function activar_desactivar_ORs()
{

	var MyID;
	var l_inactivo;
	var msj="";
	var registro;
	var itemsToChange = new Array();
	var item = 0;

	if (Ctrl("list2arr") && Ctrl("list2arr").CountRow()>0)  //si hay elementos checkeados
	{ 
		while(item < Ctrl("list2arr").CountRow())
		{                              
			MyID=Ctrl("list2arr").GetRow(item).GetAttr("id"); //Obtengo el id del elemento seleccionado

			for (var j=0; j<Ctrl("LIST2").TotalRowsCount(); j++) //para cada elemento de la lista
			{
					if (MyID == Ctrl("LIST2").GetAttrValue(j, 'id')) //si el elemento está seleccionado
					{
						l_inactivo = Ctrl("LIST2").GetAttrValue(j, 'l_inactivo');  
						registro = j; 

						if (l_inactivo == 0) //si está activo pasa a estar inactivo 
						{
						  Ctrl("LIST2").SetAttrValue(j, 'l_inactivo', 1); 
						  Ctrl('resultado').GetRow(j).SetAttr('l_inactivo', 1);    
						  //el monto se pasa a no vigente cuando se acepta  			   
						} 
						else //si está inactivo pasa a activo   validacion "Solo puede activar un OR si es válido en el tipo de carpeta." 
						{   
					      var nSQL = GetProxy().SQLService();	 
		       			var param = "<DATA oi_tipo_carpeta=\""+Ctrl('hid_tipo_carpeta').GetXValue() + "\"" + " oi_objeto_reclamo=\"" + Ctrl("LIST2").GetAttrValue(j, 'objeto_reclamo') + "\"/>";	 

	         			var objResult = nSQL.GetOBJ(Ctrl("main").getResource("esReclamoValido"),param);
	        			if(objResult.valido=="0")
	         			{                      

	         			 //obtengo descripción de objeto de reclamo
	         			 var param2 = "<DATA oi_objeto_reclamo=\"" + Ctrl("LIST2").GetAttrValue(j, 'objeto_reclamo') + "\"/>";	 
	         			 var objResult2 = nSQL.GetOBJ(Ctrl("main").getResource("GetDescObj"),param);

	         			  msj+= "No se puede activar el objeto de reclamo de " + Ctrl("LIST2").GetAttrValue(j, 'desc_sujeto') +" - " + objResult2.d_objeto_reclamo + 
		          	  " ya que no se corresponde con los permitidos por el tipo de carpeta. \r\n";
			     			}                                                      
			     			else
				   			{
					   			Ctrl("LIST2").SetAttrValue(j, 'l_inactivo', '0');  
					   			Ctrl('resultado').GetRow(j).SetAttr('l_inactivo','0');
				   			} 

						}

					}
			}//fin for cada elemento de la lista
			item++;

		}//fin while

	}//fin if elementos checkeados 

	Ctrl("LIST2").Refresh(); 

	if(msj!="")
		{	alert(msj); msj="";} 

} 

//valida que no se elimine un monto no vigente que se ha generado antes de guardar la carpeta, por haber inactivado un objeto de reclamo
function ValidarMontoSeleccionado()
{   
   var xmlResult=Ctrl("main").GetLastDocXML("DocGrilla2"); 

   for (rowMonto = xmlResult.FirstChild(); rowMonto != null; rowMonto = rowMonto.Next())
    {     
        if(Ctrl("MAIN_GRID").SelectedRowID() == rowMonto.GetAttr("oi_monto"))
        {   
            if (rowMonto.GetAttr("or_inactivo")=="1")  
            {             
		                alert('El monto seleccionado no se puede eliminar (antes de guardar los cambios en la carpeta), ya que se ha inactivado el Objeto de Reclamo asociado.');
		                return false;
            } 
        }  
    }
   return true;    
} 

//valida que no se eliminen montos no vigentes que se han generado antes de guardar la carpeta, por haber inactivado un objeto de reclamo
function ValidarMontosAlBorrar()
{
    var band = false;
    var xmlResult=Ctrl("main").GetLastDocXML("DocGrilla2"); 

    for (rowMonto = xmlResult.FirstChild(); rowMonto != null; rowMonto = rowMonto.Next())
    { 
		    if (rowMonto.GetAttr("or_inactivo")=="1")  
        {             
		         band = true; 
		         break;
         } 
    }

    if (band) 
    {
      alert('No se pueden eliminar todos los montos simultánemante (antes de guardar los cambios en la carpeta), ya que alguno de ellos ha pasado a estado No vigente por haberse inactivado un Objeto de Reclamo.'); 
      return false;                                                                               
    }

    return true;  
} 


//valida que al querer eliminar un parte, no tenga objetos de reclamo asociados
function validarEliminarParte()
{
	if(Ctrl('main').GetMode() == "EDIT-PASO2" || Ctrl('main').GetMode() == "EDIT-PARTES")
	{
	var MyID;
	var l_inactivo;
	var msj="";
	var registro;
	var itemsToDel = new Array();
	var item = 0;
	var del; 
	var xmlResult=Ctrl("main").GetLastDocXML("DocObjetosCar");  //obtengo objetos de reclamo    


	if (Ctrl("list1arr") && Ctrl("list1arr").CountRow()>0)  //si hay elementos checkeados
	{ 
		while(item < Ctrl("list1arr").CountRow()) //para cada elemento seleccionado
		{                              
			MyID=Ctrl("list1arr").GetRow(item).GetAttr("id"); //Obtengo el id del elemento seleccionado

			for (var j=0; j<Ctrl("LIST").TotalRowsCount(); j++) //para cada elemento de la lista
			{
					if (MyID == Ctrl("LIST").GetAttrValue(j, 'id')) //si el elemento está seleccionado
					{
						registro = j; 

            for (rowObj = xmlResult.FirstChild(); rowObj != null; rowObj = rowObj.Next())  //para cada objeto de reclamo
            {      
                 //si la parte tiene algún objeto de reclamo cargado
                 if(Ctrl("LIST").GetAttrValue(j, 'sujeto') == rowObj.GetAttr('sujeto') && Ctrl("LIST").GetAttrValue(j, 'rol') == rowObj.GetAttr('rol'))
                  {   
		                msj+="La parte interviniente: " + Ctrl("LIST").GetAttrValue(registro, 'desc_rol')+' - '+Ctrl("LIST").GetAttrValue(registro, 'desc_sujeto')+ " no puede eliminarse ya que posee Objetos de Reclamo asociados.\n";
		                del = 0;
		                break;
		              }
		              else
		              { del = 1;}

             } 

             if (del == 1)
             {
               	//Elimino el Elemento
			          delete arrA["k"+MyID];
    			      Ctrl('resultado').DelRowByAttr('id', MyID);
             }

           }//fin if elemento seleccionado

			}//fin for cada elemento de la lista

		item++;

		}//fin while

	}//fin if elementos checkeados 

	if(msj!="")
	{	alert(msj); msj="";}    

	refreshList("LIST", arrA);	

   } 
   else 
   { DEL();}
}


function pedidos_liq_final()
{
	var id, xmlParam;  
  if(Ctrl('main').GetMode()=='LIST') id = Ctrl("LIST").GetXValue();
  else if(Ctrl('main').GetMode()=='SHOW') id = Ctrl("oi_carpeta").GetXValue();  
  xmlParam = new NomadXML("CARPETA");
  xmlParam.SetAttr("oi_carpeta", id);  
  getFormInMain("NucleusRH.Base.Legales.PedidosLiqFinal.flow", "open_externo", xmlParam.ToString(), false);
}


function EDIT_DOCUMENTOS()
{
	if (Ctrl('main').GetMode() == "LIST" || Ctrl('main').GetMode() == "SHOW")
	{
		var id;

		if(Ctrl('main').GetMode() == "LIST")
		{
			id=Ctrl("LIST").GetXValue();
		}
		if(Ctrl('main').GetMode() == "SHOW") 
		{
		  var id = Ctrl('oi_carpeta').GetXValue();	   
		}	

		//Valido que no este Cerrada
		var nSQL = GetProxy().SQLService();	 		 
		var param = "<DATA oi_carpeta=\""+id+"\" />";	 
		var objResult = nSQL.GetOBJ(Ctrl("main").getResource("isCerrado"),param);

	  if(objResult.band=="1")
	  {    
		 alert("No se pueden modificar los documentos de una carpeta que se encuentre cerrada");
		 return false;
		}	

		//valido que no este de baja	  	 
	  var nSQL2 = GetProxy().SQLService();
	  var nSQL3 = GetProxy().SQLService();	 	 
		var param2 = "";                       		 

		var objOiBaja = nSQL2.GetOBJ(Ctrl("main").getResource("Get_oi_Baja"),param2);			
		var oiEstado = nSQL3.GetOBJ(Ctrl("main").getResource("getEstadoCarpeta"),param);			 
		if(oiEstado.oi_estado_carpeta==objOiBaja.oi)
		{
			alert("No se pueden modificar los documentos de una Carpeta dada de Baja ");
			return false;
		}
	}					 

	Ctrl('main').DoEvent("EDIT_DOCUMENTOS");
}
